#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>

// Simple hash set for integers (open addressing, linear probing)
typedef struct {
    int *keys;
    char *used;
    size_t size;
} IntHashSet;

static size_t nextPowerOfTwo(size_t n) {
    size_t p = 1;
    while (p < n) p <<= 1;
    return p;
}

static IntHashSet* createSet(size_t capacity) {
    IntHashSet *set = (IntHashSet*)malloc(sizeof(IntHashSet));
    set->size = nextPowerOfTwo(capacity * 2);
    set->keys = (int*)malloc(set->size * sizeof(int));
    set->used = (char*)calloc(set->size, sizeof(char));
    return set;
}

static void freeSet(IntHashSet *set) {
    free(set->keys);
    free(set->used);
    free(set);
}

static size_t hashInt(int x, size_t mask) {
    // simple mix
    return ((unsigned int)x * 2654435761u) & mask;
}

static void insertSet(IntHashSet *set, int x) {
    size_t mask = set->size - 1;
    size_t idx = hashInt(x, mask);
    while (set->used[idx]) {
        if (set->keys[idx] == x) return; // already present
        idx = (idx + 1) & mask;
    }
    set->used[idx] = 1;
    set->keys[idx] = x;
}

static bool containsSet(IntHashSet *set, int x) {
    size_t mask = set->size - 1;
    size_t idx = hashInt(x, mask);
    while (set->used[idx]) {
        if (set->keys[idx] == x) return true;
        idx = (idx + 1) & mask;
    }
    return false;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n, m;
        scanf("%d %d", &n, &m);
        int *arr1 = (int*)malloc(n * sizeof(int));
        int *arr2 = (int*)malloc(m * sizeof(int));
        for (int i = 0; i < n; ++i) scanf("%d", &arr1[i]);
        for (int i = 0; i < m; ++i) scanf("%d", &arr2[i]);
        // Build set from smaller array
        IntHashSet *set;
        if (n <= m) {
            set = createSet(n);
            for (int i = 0; i < n; ++i) insertSet(set, arr1[i]);
            int ans = -1;
            for (int i = 0; i < m; ++i) if (containsSet(set, arr2[i]) && arr2[i] > ans) ans = arr2[i];
            printf("%d\n", ans);
        } else {
            set = createSet(m);
            for (int i = 0; i < m; ++i) insertSet(set, arr2[i]);
            int ans = -1;
            for (int i = 0; i < n; ++i) if (containsSet(set, arr1[i]) && arr1[i] > ans) ans = arr1[i];
            printf("%d\n", ans);
        }
        freeSet(set);
        free(arr1);
        free(arr2);
    }
    return 0;
}

