int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--) {
        int n,m; cin>>n>>m;
        vector<int> a(n), b(m);
        for(int &x: a) cin>>x;
        for(int &x: b) cin>>x;
        // put smaller array into unordered_set
        if(n>m) swap(a,b), swap(n,m);
        unordered_set<int> s;
        s.reserve(n*2);
        for(int x: a) s.insert(x);
        int ans = -1;
        for(int x: b) if(s.count(x) && x>ans) ans = x;
        cout<<ans<<"\n";
    }
    return 0;
}

