#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        n = int(next(it)); m = int(next(it))
        arr1 = [int(next(it)) for _ in range(n)]
        arr2 = [int(next(it)) for _ in range(m)]
        # use the smaller list for the set
        if n > m:
            arr1, arr2 = arr2, arr1
        s = set(arr1)
        ans = -1
        for x in arr2:
            if x in s and x > ans:
                ans = x
        out_lines.append(str(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

